Add metric instrumentation to the health check code in `health.rs`.

## Instrumentation Points

### Health Check Results
```rust
// In run_health_checks() after each proxy check
let result_label = if result.success { "healthy" } else { "unhealthy" };
metrics::HEALTH_CHECKS
    .with_label_values(&[&proxy.id, result_label])
    .inc();

// Also update the gauge
metrics::PROXY_HEALTH
    .with_label_values(&[&proxy.id])
    .set(if result.success { 1.0 } else { 0.0 });
```

### Health Check Latency
```rust
// Record latency for successful checks
if result.success {
    metrics::HEALTH_CHECK_LATENCY
        .with_label_values(&[&proxy.id])
        .observe(result.latency_ms / 1000.0);  // Convert ms to seconds
}
```

### Failover Events
```rust
// In check_and_perform_failover() when failover occurs
if let Some(event) = check_and_perform_failover(&config, &state, &runtime).await {
    metrics::FAILOVERS
        .with_label_values(&[&event.from_proxy, &event.to_proxy])
        .inc();
    // ... rest of failover handling
}
```

### Failback Events
```rust
// In health_check_loop when failback occurs
if check_and_perform_failback(&config, &state, &runtime).await {
    let original = runtime.get_original_proxy().await;
    if let (Some(from), Some(to)) = (runtime.get_effective_proxy().await, original) {
        metrics::FAILOVERS
            .with_label_values(&[&from, &to])
            .inc();
    }
    // ... rest of failback handling
}
```

