Implement the logic to determine correct installation paths and write completion scripts for each supported shell.

## Implementation Details

### Installation Paths

```rust
impl Shell {
    pub fn completion_path(&self) -> Result<PathBuf> {
        let home = dirs::home_dir()
            .ok_or_else(|| anyhow::anyhow!("Could not determine home directory"))?;

        Ok(match self {
            Shell::Bash => {
                // XDG spec: ~/.local/share/bash-completion/completions/
                let xdg_data = std::env::var("XDG_DATA_HOME")
                    .map(PathBuf::from)
                    .unwrap_or_else(|_| home.join(".local/share"));
                xdg_data.join("bash-completion/completions/rp")
            }
            Shell::Zsh => {
                // Check if ~/.zsh/completions exists or can be created
                // Alternatively, use first writable dir in $fpath
                home.join(".zsh/completions/_rp")
            }
            Shell::Fish => {
                // Fish XDG: ~/.config/fish/completions/
                let xdg_config = std::env::var("XDG_CONFIG_HOME")
                    .map(PathBuf::from)
                    .unwrap_or_else(|_| home.join(".config"));
                xdg_config.join("fish/completions/rp.fish")
            }
            Shell::Unknown => anyhow::bail!("Cannot install completions for unknown shell"),
        })
    }

    pub fn activation_hint(&self) -> &'static str {
        match self {
            Shell::Bash => "Restart your shell or run: source ~/.bashrc",
            Shell::Zsh => "Restart your shell or run: compinit",
            Shell::Fish => "Completions are active automatically",
            Shell::Unknown => "",
        }
    }
}
```

### Installation Logic

```rust
pub fn install_completions(shell: Shell, dry_run: bool) -> Result<PathBuf> {
    let path = shell.completion_path()?;
    let script = generate_completions(shell);

    if dry_run {
        println!("Would install {} completions to {}", shell.name(), path.display());
        return Ok(path);
    }

    // Create parent directory if needed
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)
            .with_context(|| format!("Failed to create {}", parent.display()))?;
    }

    // Write script
    std::fs::write(&path, &script)
        .with_context(|| format!("Failed to write {}", path.display()))?;

    Ok(path)
}
```

### Zsh fpath Handling

Zsh requires the completion directory to be in `$fpath`. Check and warn:

```rust
fn check_zsh_fpath(completion_dir: &Path) -> bool {
    if let Ok(fpath) = std::env::var("fpath") {
        fpath.split(':').any(|p| Path::new(p) == completion_dir)
    } else {
        false
    }
}

// If not in fpath, suggest adding to .zshrc:
// fpath=(~/.zsh/completions $fpath)
// autoload -Uz compinit && compinit
```

