Would disable service: systemctl disable rp
Would remove /etc/systemd/system/rp.service
Would run: systemctl daemon-reload

No changes made (dry-run mode)
```

### Implementation

```rust
pub fn service_install(args: ServiceInstallArgs) -> Result<()> {
    let ctx = if args.dry_run {
        Some(DryRunContext::new())
    } else {
        None
    };

    let service_path = PathBuf::from("/etc/systemd/system/rp.service");

    if let Some(ref ctx) = ctx {
        ctx.would_do(&format!("Copy service file to {}", service_path.display()));
        ctx.would_do("Run: systemctl daemon-reload");
        if args.enable {
            ctx.would_do("Run: systemctl enable rp");
        }
        if args.start {
            ctx.would_do("Run: systemctl start rp");
        }

        println!("{}", ctx.format());
        println!("\nNo changes made (dry-run mode)");
        return Ok(());
    }

    // Actual install logic
    // ...
}

pub fn service_uninstall(args: ServiceUninstallArgs) -> Result<()> {
    let ctx = if args.dry_run {
        Some(DryRunContext::new())
    } else {
        None
    };

    let service_path = PathBuf::from("/etc/systemd/system/rp.service");

    if let Some(ref ctx) = ctx {
        if service_is_active() {
            ctx.would_do("Stop service: systemctl stop rp");
        }
        if service_is_enabled() {
            ctx.would_do("Disable service: systemctl disable rp");
        }
        if service_path.exists() {
            ctx.would_do(&format!("Remove {}", service_path.display()));
        }
        ctx.would_do("Run: systemctl daemon-reload");

        println!("{}", ctx.format());
        println!("\nNo changes made (dry-run mode)");
        return Ok(());
    }

    // Actual uninstall logic
    // ...
}
```

### Edge Cases

- Service file doesn't exist: "Nothing to uninstall"
- Service not running: Skip "would stop" message
- Permission issues: Show what would be attempted (user can see sudo is needed)

